const fs = require('fs');
const query = ($json.body && $json.body.query) || ($json.query) || '';
const dbPath = '/home/lucy-ubuntu/Escritorio/NIN/memoria/agente_memoria.db'.replace('agente_memoria.db', 'memory_store.json');
try {
  let store = {};
  if (fs.existsSync(dbPath)) store = JSON.parse(fs.readFileSync(dbPath, 'utf8'));
  const results = Object.entries(store)
    .filter(([k, v]) => k.includes(query) || (v.value && v.value.includes(query)))
    .sort((a, b) => (b[1].score || 1) - (a[1].score || 1))
    .slice(0, 5);
  if (results.length === 0) return [{ json: { output: '🔍 No se encontró memoria previa para: ' + query, found: false } }];
  const formatted = results.map(([k, v]) => `• ${k}: ${v.value} (score: ${v.score || 1})`).join('\n');
  return [{ json: { output: '🧠 Memorias encontradas:\n' + formatted, found: true } }];
} catch(e) {
  return [{ json: { output: '❌ Error: ' + e.message, found: false } }];
}
